try {
  const biz = $('Loop Each Business').first().json;
  const perf = $('Fetch Performance History').all().map(i => i.json);
  const comp = $('Fetch Competitor Insight').all().map(i => i.json);
  const stats = $('Fetch Daily Stats').all().map(i => i.json);

  const avgRoas = perf.length ? (perf.reduce((s,p) => s + (p.roas||0), 0) / perf.length).toFixed(2) : 'N/A';
  const avgCtr = perf.length ? (perf.reduce((s,p) => s + (p.ctr||0), 0) / perf.length).toFixed(3) : 'N/A';
  const totalReach = stats.length ? stats.reduce((s,d) => s + (d.total_reach||0), 0) : 0;
  const compInsight = comp.length ? comp[0].content_to_steal || '' : '';
  const gapOpp = comp.length ? comp[0].gap_opportunity || '' : '';
  // Intelligence Layer
  const brandVoice = biz.brand_voice_locked || 'professional and friendly';
  const dreamCustomer = biz.dream_customer || biz.target_audience || 'general audience';
  const differentiator = biz.unique_differentiator || 'exceptional quality and service';
  const bestThemes = JSON.stringify(biz.best_performing_themes || []);
  const worstThemes = JSON.stringify(biz.worst_performing_themes || []);
  const aiDecisions = biz.ai_brain_decisions ? JSON.stringify(biz.ai_brain_decisions).substring(0,400) : 'First run';


  const prompt = `You are an expert marketing strategist. Generate a full week of high-performance marketing content.

BUSINESS PROFILE:
- Name: ${biz.business_name || 'Unknown'}
- Industry: ${biz.industry || 'General'}
- Location: ${biz.location || 'Unknown'}
- Target Audience: ${biz.target_audience || 'General public'}
- Brand Tone: ${biz.brand_tone || 'Professional and friendly'}
- Marketing Goal: ${biz.marketing_goal || 'Grow brand awareness'}
- Plan: ${biz.plan || 'free'}

PERFORMANCE DATA (last 4 periods):
- Average ROAS: ${avgRoas}
- Average CTR: ${avgCtr}%
- Weekly Reach: ${totalReach} people
- Total Followers Gained: ${biz.followers_gained || 0}
- Posts Published: ${biz.posts_published || 0}

COMPETITOR INTELLIGENCE:
- What competitors do well: ${compInsight || 'N/A'}
- Gap opportunity for us: ${gapOpp || 'N/A'}

INTELLIGENCE LAYER — use this to supercharge results:
- Brand Voice Locked: ${brandVoice}
- Dream Customer: ${dreamCustomer}
- Unique Differentiator: ${differentiator}
- Best Performing Themes (double down): ${bestThemes}
- Avoid These Themes (poor performance): ${worstThemes}
- Latest AI Strategy Decision: ${aiDecisions}

CONTENT REQUIREMENTS:
- Create content that outperforms current ${avgCtr}% CTR
- Leverage the gap opportunity identified above
- Tailor content specifically for ${biz.industry} industry in ${biz.location}
- Match the brand tone: ${biz.brand_tone}

Return ONLY a valid JSON object with exactly these 10 keys (no markdown, no explanation, no code fences):
{
  "instagram_caption": "engaging Instagram post with emojis and 5+ relevant hashtags",
  "instagram_caption_2": "second Instagram post variation with different angle",
  "facebook_post": "longer Facebook post (150-200 words) with storytelling and CTA",
  "instagram_story_text": "3 punchy lines max, designed for swipe-up engagement",
  "email_subject": "high open-rate email subject line (personalized, curiosity-driven)",
  "email_body": "full email body 3-4 paragraphs, conversational, ends with clear CTA",
  "blog_title": "SEO-optimized blog title targeting local keywords",
  "google_ad_headline": "Google ad headline max 30 chars, benefit-focused",
  "google_ad_description": "Google ad description max 90 chars with CTA",
  "content_theme": "2-4 word theme for this week"
}`;

  return [{ json: { prompt, biz } }];
} catch(e) {
  return [{ json: { error: e.message, prompt: 'Generate marketing content for a local business. Return only valid JSON with 10 keys: instagram_caption, instagram_caption_2, facebook_post, instagram_story_text, email_subject, email_body, blog_title, google_ad_headline, google_ad_description, content_theme', biz: {} } }];
}

try {
  const raw = $input.first().json.content?.[0]?.text || '';
  let c = {};
  try { c = JSON.parse(raw); }
  catch(e) { const m = raw.match(/\{[\s\S]*\}/); if(m) try { c = JSON.parse(m[0]); } catch(e2) {} }

  const biz = $('Build Smart Prompt').first().json.biz || {};

  // Quality scoring
  let score = 0;
  if ((c.instagram_caption||'').length > 100) score += 15;
  if ((c.instagram_caption||'').includes('#')) score += 10;
  if ((c.facebook_post||'').length > 200) score += 15;
  if ((c.email_body||'').length > 300) score += 15;
  if ((c.email_subject||'').length > 10) score += 10;
  if ((c.google_ad_headline||'').length <= 30 && c.google_ad_headline) score += 10;
  if ((c.google_ad_description||'').length <= 90 && c.google_ad_description) score += 10;
  if (c.content_theme) score += 10;
  if ((c.instagram_caption||'').toLowerCase().includes(biz.location?.toLowerCase()||'zzz')) score += 5;

  return [{ json: { ...c, quality_score: score, biz } }];
} catch(e) {
  return [{ json: { quality_score: 0, error: e.message, biz: {} } }];
}

